"""Utilities for converting JSONPath expressions to JSON Schemas."""

import json
from typing import Any, Dict, List, Tuple


def json_path_to_schema(path: str) -> str:
    """
    Convert a JSONPath expression to a minimal JSON Schema string.

    The generated schema constrains generated JSON to contain the structure
    implied by the path.  For example::

        "$.store.book[*].author"
        ->
        {
          "type": "object",
          "properties": {
            "store": {
              "type": "object",
              "properties": {
                "book": {
                  "type": "array",
                  "items": {
                    "type": "object",
                    "properties": {"author": {}},
                    "required": ["author"]
                  }
                }
              },
              "required": ["book"]
            }
          },
          "required": ["store"]
        }

    Supported path syntax:
      - ``$``              root
      - ``.key``           object property (dot notation)
      - ``['key']``        object property (bracket notation, single or double quotes)
      - ``[*]``            array with arbitrary items
      - ``[N]``            array index (treated as ``[*]`` at schema level)

    Graceful fallbacks (returns ``{}`` — any valid JSON):
      - ``..``             recursive descent
      - ``.*``             wildcard key

    Args:
        path: A JSONPath string starting with ``$``.

    Returns:
        A JSON Schema string (serialised JSON).

    Raises:
        ValueError: If *path* does not start with ``$``.
    """
    if not path.startswith("$"):
        raise ValueError(f"JSONPath must start with '$', got: {path!r}")

    tokens = _tokenize(path[1:])  # strip leading '$'
    schema = _build_schema(tokens)
    return json.dumps(schema)


# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------

# Token types emitted by _tokenize
_TOK_KEY = "key"        # ('key', name:str)
_TOK_ARRAY = "array"    # ('array',)
_TOK_WILDCARD = "wildcard"    # ('wildcard',)  -> fall back to {}
_TOK_RECURSIVE = "recursive"  # ('recursive',) -> fall back to {}


def _tokenize(path_tail: str) -> List[Tuple]:
    """
    Tokenize the portion of a JSONPath that follows the leading ``$``.

    Returns a list of token tuples in *left-to-right* (outermost-first) order.
    """
    tokens: List[Tuple] = []
    i = 0
    n = len(path_tail)

    while i < n:
        ch = path_tail[i]

        if ch == ".":
            # Peek ahead
            if i + 1 < n and path_tail[i + 1] == ".":
                # Recursive descent  ``..``
                tokens.append((_TOK_RECURSIVE,))
                i += 2
                # Consume any key that follows the ``..`` (e.g. ``..author``)
                # – it only restricts which descendants to select, but at the
                # schema level we already fall back to {}.
                while i < n and path_tail[i] not in ".[]":
                    i += 1
            elif i + 1 < n and path_tail[i + 1] == "*":
                # Wildcard  ``.*``
                tokens.append((_TOK_WILDCARD,))
                i += 2
            else:
                # Normal property  ``.key``
                i += 1  # skip the '.'
                key_start = i
                while i < n and path_tail[i] not in ".[]":
                    i += 1
                key = path_tail[key_start:i]
                if key:
                    tokens.append((_TOK_KEY, key))

        elif ch == "[":
            # Find matching ']'
            try:
                j = path_tail.index("]", i)
            except ValueError:
                # Malformed – skip to end
                break
            content = path_tail[i + 1 : j].strip()
            i = j + 1

            if content == "*":
                tokens.append((_TOK_ARRAY,))
            elif content.lstrip("-").isdigit():
                # Numeric index – treat as "any array element" at schema level
                tokens.append((_TOK_ARRAY,))
            elif len(content) >= 2 and content[0] in ('"', "'") and content[0] == content[-1]:
                # Quoted key  ``['key']`` or ``["key"]``
                tokens.append((_TOK_KEY, content[1:-1]))
            else:
                # Unknown bracket expression – fall back
                tokens.append((_TOK_WILDCARD,))

        else:
            # Unexpected character – skip
            i += 1

    return tokens


def _build_schema(tokens: List[Tuple]) -> Dict[str, Any]:
    """
    Build a JSON Schema dict from tokenised path segments.

    Constructs the schema inside-out (starting from the innermost / deepest
    element and wrapping it with each successive outer container).
    """
    if not tokens:
        return {}

    # If any token forces a fall-back, return the permissive schema immediately.
    for tok in tokens:
        if tok[0] in (_TOK_WILDCARD, _TOK_RECURSIVE):
            return {}

    # Build from right (deepest) to left (shallowest).
    schema: Dict[str, Any] = {}
    for tok in reversed(tokens):
        kind = tok[0]
        if kind == _TOK_KEY:
            key = tok[1]
            schema = {
                "type": "object",
                "properties": {key: schema},
                "required": [key],
            }
        elif kind == _TOK_ARRAY:
            schema = {
                "type": "array",
                "items": schema,
            }
        # _TOK_WILDCARD / _TOK_RECURSIVE already handled above

    return schema

